/**
 * verify-mechsense-core.js
 * mechsense-core.js の計算検証スクリプト
 * 既存の verify-calc.js の結果と照合する
 * 実行: node verify-mechsense-core.js
 */

'use strict';

const MechSense = require('../mechsense-core.js');
const { Spring, Utils } = MechSense;

console.log(`MechSense v${MechSense.version} 計算検証\n${'='.repeat(50)}`);

let passed = 0;
let failed = 0;

function check(label, actual, expected, tol = 0.01) {
  const ok = Math.abs(actual - expected) <= tol * Math.abs(expected) + 1e-9;
  if (ok) {
    console.log(`  ✅ ${label}: ${actual.toFixed(4)}`);
    passed++;
  } else {
    console.log(`  ❌ ${label}: ${actual.toFixed(4)} (期待: ${expected.toFixed(4)})`);
    failed++;
  }
}

function checkEq(label, actual, expected) {
  if (actual === expected) {
    console.log(`  ✅ ${label}: ${actual}`);
    passed++;
  } else {
    console.log(`  ❌ ${label}: ${actual} (期待: ${expected})`);
    failed++;
  }
}

// ── ケース1: 基本例（SW-B, d=2.0, D=15, Na=5, P=50）
console.log('\n[ケース1] SW-B d=2.0 D=15 Na=5 P=50');
{
  const r = Spring.calc({ d: 2.0, D: 15, Na: 5, P: 50, mat: 'SW-B' });
  if (r.error) { console.log(`  ❌ エラー: ${r.error}`); failed++; }
  else {
    check('C (ばね指数)', r.C, 7.5);
    check('K (Wahl係数)', r.K, 1.1974, 0.001);
    check('k (ばね定数 N/mm)', r.k, 9.3037, 0.001);
    check('δ (たわみ mm)', r.delta, 5.374, 0.01);
    check('τ (MPa)', r.tau, 285.85, 0.005);
    check('Lc (密着高さ mm)', r.Lc, 14.0);
    check('τ/σB (応力比)', r.ratio, 0.1945, 0.005);
    checkEq('status', r.status, 'OK');
    checkEq('isSafe', r.isSafe, true);
  }
}

// ── ケース2: 中規模（SW-C, d=3.2, D=20, Na=8, P=100）
console.log('\n[ケース2] SW-C d=3.2 D=20 Na=8 P=100');
{
  const r = Spring.calc({ d: 3.2, D: 20, Na: 8, P: 100, mat: 'SW-C' });
  if (r.error) { console.log(`  ❌ エラー: ${r.error}`); failed++; }
  else {
    const C = 20 / 3.2;                                          // 6.25
    const K = (4*C-1)/(4*C-4) + 0.615/C;
    const k = 78500 * Math.pow(3.2,4) / (8 * Math.pow(20,3) * 8);
    const tau = 8 * 100 * 20 * K / (Math.PI * Math.pow(3.2,3));
    const sigmaB = Spring.getSigmaB('SW-C', 3.2);              // 1570
    check('C', r.C, C);
    check('K', r.K, K);
    check('k', r.k, k);
    check('τ', r.tau, tau);
    check('τ/σB', r.ratio, tau / sigmaB);
    checkEq('status', r.status, 'OK');
  }
}

// ── ケース3: 境界条件 C=4（SW-C, d=4.0, D=16, Na=10, P=200）
console.log('\n[ケース3] 境界条件 C=4  SW-C d=4.0 D=16 Na=10 P=200');
{
  const r = Spring.calc({ d: 4.0, D: 16, Na: 10, P: 200, mat: 'SW-C' });
  if (r.error) { console.log(`  ❌ エラー: ${r.error}`); failed++; }
  else {
    check('C', r.C, 4.0);
    checkEq('cRange', r.cRange, true);   // C=4 は境界値で OK
    checkEq('isSafe', r.isSafe, true);
    checkEq('status', r.status, 'OK');
  }
}

// ── ケース4: 応力超過（SW-B, d=1.0, D=15, Na=5, P=200）
console.log('\n[ケース4] 応力超過  SW-B d=1.0 D=15 Na=5 P=200');
{
  const r = Spring.calc({ d: 1.0, D: 15, Na: 5, P: 200, mat: 'SW-B' });
  if (r.error) { console.log(`  ❌ エラー: ${r.error}`); failed++; }
  else {
    checkEq('status', r.status, 'NG_STRESS');
    checkEq('stressOK', r.stressOK, false);
    checkEq('warnings.length > 0', r.warnings.length > 0, true);
  }
}

