   */
  calc: function () {
    throw new Error('MechSense.Bolt.calc: 未実装（JIS B 1083 対応予定）');
  },
};


// ─────────────────────────────────────────────
// Resonance モジュール（JIS B 1234 — 将来実装）
// ─────────────────────────────────────────────

const Resonance = {
  /**
   * @todo JIS B 1234 共振点計算を実装する
