164	      preset: false, tauLimit: 0.45,
165	      Lf: null, deltaMax: null, P_solid: null, bottomOut: false, lambda: null,
166	      stressOK: false, cRange: false, isSafe: false,
167	      status: 'NG_STRESS',
168	      warnings: [],
169	    };
170	
171	    // バリデーション
172	    const material = SPRING_MATERIALS[matKey];
173	    if (!material) {
174	      result.error = `材料データが見つかりません: ${matKey}`;
175	      return result;
176	    }
177	    if (isNaN(d) || d <= 0)  { result.error = '線径 d が無効です'; return result; }
178	    if (isNaN(D) || D <= 0)  { result.error = '中心径 D が無効です'; return result; }
179	    if (isNaN(Na) || Na <= 0){ result.error = '有効巻数 Na が無効です'; return result; }
180	    if (isNaN(P) || P < 0)   { result.error = '荷重 P が無効です'; return result; }
181	
182	    const G      = material.G;
183	    const sigmaB = springGetSigmaB(matKey, d);
184	    const C      = D / d;
185	
186	    if (C < 2) {
