191	    // JIS B 2704 計算式
192	    const K     = (4 * C - 1) / (4 * C - 4) + 0.615 / C;
193	    const k     = G * Math.pow(d, 4) / (8 * Math.pow(D, 3) * Na);
194	    const delta = k > 0 ? P / k : 0;
195	    const tau   = 8 * P * D * K / (Math.PI * Math.pow(d, 3));
196	    const ratio = tau / sigmaB;
197	    const Lc    = (Na + 2) * d;
198	    const Do    = D + d;
199	    const Di    = D - d;
200	    const Nt    = Na + 2;
201	
