213	        result.error = `自由長 Lf = ${lfVal} mm が密着高さ Lc = ${Lc.toFixed(2)} mm 以下です`;
214	        return result;
215	      }
216	      deltaMax  = lfVal - Lc;
217	      P_solid   = k * deltaMax;
218	      bottomOut = P >= P_solid;
219	      lambda    = lfVal / D;
220	      if (bottomOut) {
221	        lfWarnings.push(`底付き: P=${P}N が密着荷重 P_solid=${P_solid.toFixed(1)}N 以上です。荷重を下げるか Lf を増やしてください。`);
222	      } else if (P > 0.8 * P_solid) {
223	        lfWarnings.push(`底付き接近: P は密着荷重の${(P / P_solid * 100).toFixed(0)}%です（P_solid=${P_solid.toFixed(1)}N）。`);
224	      }
225	      if (lambda > 4) {
226	        lfWarnings.push(`座屈注意: Lf/D = ${lambda.toFixed(2)} > 4。座屈ガイドの使用を検討してください。`);
227	      }
228	    }
